+const EMBED_BASE_SANDBOX = "allow-scripts allow-popups allow-forms";
+const EMBED_SANDBOX_WITH_SAME_ORIGIN = `${EMBED_BASE_SANDBOX} allow-same-origin`;
+
+const escapeHtmlAttr = (value: string) =>
+  value
+    .replaceAll("&", "&amp;")
+    .replaceAll('"', "&quot;")
+    .replaceAll("<", "&lt;")
+    .replaceAll(">", "&gt;");
+
+const toSafeSrcdoc = (html: string) => {
+  const doc = new DOMParser().parseFromString(html, "text/html");
+
+  // We only allow a very small subset and rebuild the markup ourselves.
+  // This prevents HTML/script injection via untrusted oEmbed/html payloads.
+  const iframe = doc.querySelector("iframe[src]");
+  if (iframe) {
+    const src = iframe.getAttribute("src");
+    if (!src) {
+      return null;
+    }
+    const safeSrc = new URL(src, "https://excalidraw.com").toString();
+    return `<iframe src="${escapeHtmlAttr(safeSrc)}"></iframe>`;
+  }
+
+  const script = doc.querySelector("script[src]");
+  if (script) {
+    const src = script.getAttribute("src");
+    if (!src) {
+      return null;
+    }
+    const safeSrc = new URL(src, "https://excalidraw.com").toString();
+    return `<script src="${escapeHtmlAttr(safeSrc)}"></script>`;
+  }
+
+  return null;
+};
